bd list --status=in_progress --json --limit=0 2>/dev/null | python3 -c "
import json, sys
data = json.load(sys.stdin)
polecats = [b for b in data if b.get('assignee','') and 'polecats/' in str(b.get('assignee',''))]
if polecats:
    for p in polecats:
        print(f'{p[\"id\"]} assigned to {p.get(\"assignee\",\"\")} - {p[\"title\"]}')
else:
    print('No in_progress beads assigned to polecats')
" 2>/dev/null || echo "No in_progress beads"

